import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1971年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1971年/核心总结.md","filePath":"01_letters/1971年/核心总结.md"}'),d={name:"01_letters/1971年/核心总结.md"};function l(n,t,i,h,s,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_1971年-核心总结" tabindex="-1">1971年 核心总结 <a class="header-anchor" href="#_1971年-核心总结" aria-label="Permalink to &quot;1971年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> 剔除资本利得后营业收益超过股东权益14%，大幅跑赢行业均值。但巴菲特清醒地指出，从低基数提升容易，维持高位更难。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1971年</th><th>对比</th></tr></thead><tbody><tr><td>营业收益/期初股东权益</td><td><strong>&gt;14%</strong></td><td>远超美国行业均值</td></tr><tr><td>纺织业务</td><td>微利</td><td>艰难求生</td></tr><tr><td>保险核心</td><td>保费规模下降</td><td>费率充足，承保盈利</td></tr><tr><td>再保险</td><td>保费规模可观</td><td>费率充足</td></tr></tbody></table><h2 id="业务亮点与隐忧" tabindex="-1">业务亮点与隐忧 <a class="header-anchor" href="#业务亮点与隐忧" aria-label="Permalink to &quot;业务亮点与隐忧&quot;">​</a></h2><h3 id="银行业务-常胜将军" tabindex="-1">银行业务：常胜将军 <a class="header-anchor" href="#银行业务-常胜将军" aria-label="Permalink to &quot;银行业务：常胜将军&quot;">​</a></h3><p>Gene Abegg 和 Bob Kline 管理的伊利诺伊国民银行，1971年税后存款收益率远超2%，同时：</p><ul><li>几乎不使用借入资金</li><li>流动性远高于行业均值</li><li>贷款损失率极低</li><li>定期存款占比超50%</li></ul><p>这是银行创办40年来持续领先行业的缩影。巴菲特称其&quot;盈利能力领跑行业&quot;。</p><h3 id="保险业务-规模收缩-利润优先" tabindex="-1">保险业务：规模收缩，利润优先 <a class="header-anchor" href="#保险业务-规模收缩-利润优先" aria-label="Permalink to &quot;保险业务：规模收缩，利润优先&quot;">​</a></h3><p>1971年是保险盈利大年——全行业承保利润率创历史新高。但伯克希尔的保险掌门人 Jack Ringwalt 和 Phil Liesche 保持清醒：</p><p><strong>&quot;我们始终将承保盈利作为首要目标，这意味着1972年国民赔偿保险公司的直接保费规模很可能出现大幅下滑。&quot;</strong></p><p>这一选择后来被证明极为正确——1972年大量竞争对手用低费率抢市场，随后遭遇惨痛亏损。</p><h3 id="三个值得关注的扩张信号" tabindex="-1">三个值得关注的扩张信号 <a class="header-anchor" href="#三个值得关注的扩张信号" aria-label="Permalink to &quot;三个值得关注的扩张信号&quot;">​</a></h3><p><strong>① 本土州模式快速复制</strong></p><ul><li>1970年：内布拉斯加意外保险公司（HomeState）</li><li>1971年：明尼苏达莱克兰火灾与意外保险公司</li><li>1972年：德克萨斯联合保险公司</li></ul><p>John Ringwalt 负责，统一采用&quot;单一深耕州市场+本地化触达&quot;策略。</p><p><strong>② 收购芝加哥家庭与汽车保险公司</strong> 维克·拉布（Vic Raab）以一笔小额初始投资，将这家公司打造成库克县主要汽车险公司，1971年保费规模约750万美元。</p><p>这是巴菲特首次系统性地投资城市汽车险市场，后来这家公司的模式在佛罗里达和加州复制。</p><p><strong>③ 再保险快速成规模</strong> George Young 仅用两年时间，将再保险业务发展到&quot;可观的规模&quot;。浮存金来源急剧扩大。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：伯克希尔的盈利质量在改善</strong></p><p>1965年接手时，盈利几乎全靠纺织（且不稳定）。到1971年，保险和银行已接管盈利主力，纺织从&quot;决定公司命运&quot;变为&quot;贡献有限但稳定&quot;的角色。资本配置的成效肉眼可见。</p><p><strong>洞察二：规模收缩≠战略失败</strong></p><p>当 Jack Ringwalt 主动减少保费规模时，一些投资者可能会误读为业务萎缩。巴菲特在年报中特意解释：&quot;我们从未设定规模目标——在再保险业务中更是如此，因为只要放弃盈利标准，几乎任何规模的业务都能拿到。&quot;</p><p>这是伯克希尔最重要的文化基因之一：<strong>宁可不增长，也不做赔本买卖。</strong></p><p><strong>洞察三：创始人型管理人才是核心资产</strong></p><p>三家最重要的子公司——国民赔偿保险（Jack Ringwalt）、伊利诺伊国民银行（Gene Abegg）、家庭与汽车保险公司（Vic Raab）——全部是创始人型企业家。巴菲特后来总结的&quot;德才兼备&quot;选人标准，1971年已在实践中成型。</p><h2 id="名言" tabindex="-1">名言 <a class="header-anchor" href="#名言" aria-label="Permalink to &quot;名言&quot;">​</a></h2><blockquote><p>&quot;当整个行业在&#39;分享&#39;繁荣的时候，我们也分到了一杯羹。但我们意识到，这背后也存在隐忧。&quot; ——沃伦·巴菲特，1971年年报</p></blockquote><p>（解读：行业景气时所有人都在赚钱，但巴菲特已经预感到繁荣不可持续，所以主动收缩保费规模。这种&quot;别人贪婪时恐惧&quot;的本能，在1970年代初就已清晰可见。）</p><h2 id="重要人事" tabindex="-1">重要人事 <a class="header-anchor" href="#重要人事" aria-label="Permalink to &quot;重要人事&quot;">​</a></h2><table tabindex="0"><thead><tr><th>人物</th><th>角色</th><th>亮点</th></tr></thead><tbody><tr><td>Gene Abegg</td><td>银行 CEO</td><td>40年持续顶级回报</td></tr><tr><td>Bob Kline</td><td>银行行长</td><td>存款营销出色</td></tr><tr><td>Jack Ringwalt</td><td>国民赔偿保险 CEO</td><td>规模收缩守护利润</td></tr><tr><td>Vic Raab</td><td>家庭汽车保险创始人</td><td>750万美元保费的城市险专家</td></tr><tr><td>George Young</td><td>再保险负责人</td><td>两年做成可观的再保险规模</td></tr></tbody></table><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><ul><li>距离1956年巴菲特合伙基金：<strong>15年</strong></li><li>距离1965年接手伯克希尔：<strong>6年</strong></li><li>距离1972年历史最高ROE（19.8%）：<strong>1年</strong></li></ul>',35)])])}const q=a(d,[["render",l]]);export{c as __pageData,q as default};
